'use client';

import Image from 'next/image';
import { Github, Linkedin, Code, Brain, Globe } from 'lucide-react';

export default function Hero() {
  return (
    <section className="relative min-h-screen flex items-center justify-center px-6 overflow-hidden">

      {/* 🔥 GRID BACKGROUND */}
      <div className="absolute inset-0 z-0">
        <div className="absolute inset-0 bg-[#020617]" />
        
        {/* grid */}
        <div className="absolute inset-0 opacity-[0.08] bg-[linear-gradient(to_right,#00f2ff_1px,transparent_1px),linear-gradient(to_bottom,#00f2ff_1px,transparent_1px)] bg-[size:60px_60px]" />
        
        {/* glow */}
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_50%_30%,rgba(0,242,255,0.15),transparent_70%)]" />
      </div>

      {/* CONTENT */}
      <div className="relative z-10 text-center max-w-4xl">

        {/* Badge */}
        <div className="inline-block px-4 py-1 rounded-full border border-cyan-400/20 bg-cyan-400/5 text-cyan-400 text-xs tracking-widest uppercase mb-6">
          Available for new projects
        </div>

        {/* Name */}
        <h1 className="text-4xl md:text-5xl font-bold text-white mb-3">
          MD. Shohrab Hossain
        </h1>

        {/* Role */}
        <h2 className="text-3xl md:text-4xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 to-blue-500 mb-6">
          Software Engineer
        </h2>

        {/* Description */}
        <p className="text-gray-400 max-w-xl mx-auto mb-10 leading-relaxed">
          Architecting high-performance scalable systems and intuitive digital experiences
          with a focus on technical precision and elegant code.
        </p>

        {/* 🔥 AVATAR */}
        <div className="relative w-56 h-56 mx-auto mb-10">

          {/* glow ring */}
          <div className="absolute inset-0 rounded-full border border-cyan-400/40 shadow-[0_0_30px_rgba(0,242,255,0.5)]"></div>

          <div className="absolute inset-2 rounded-full overflow-hidden">
            <Image
              src="/shohrab.jpg"
              alt="Shohrab"
              fill
              className="object-cover"
            />
          </div>

          {/* Floating icons */}
          {[Code, Brain, Globe].map((Icon, i) => (
            <div
              key={i}
              className="absolute w-10 h-10 rounded-xl bg-white/5 backdrop-blur border border-white/10 flex items-center justify-center"
              style={{
                top: i === 0 ? '-10px' : i === 1 ? '50%' : 'auto',
                left: i === 1 ? '-20px' : 'auto',
                right: i === 0 ? '-10px' : i === 2 ? '-20px' : 'auto',
                bottom: i === 2 ? '-10px' : 'auto',
              }}
            >
              <Icon className="w-4 h-4 text-cyan-400" />
            </div>
          ))}
        </div>

        {/* CTA */}
        <div className="flex justify-center gap-4 mb-8">
          <a
            href="#projects"
            className="px-6 py-3 rounded-xl bg-cyan-400 text-black font-semibold hover:scale-105 transition"
          >
            View Projects ↓
          </a>

          <a
            href="#contact"
            className="px-6 py-3 rounded-xl border border-white/20 text-white hover:bg-white/10 transition"
          >
            Let's Talk
          </a>
        </div>

        {/* Social */}
        <div className="flex justify-center gap-6 text-gray-400">
          <a href="#" className="hover:text-cyan-400">
            <Github />
          </a>
          <a href="#" className="hover:text-cyan-400">
            <Linkedin />
          </a>
        </div>
      </div>
    </section>
  );
}